#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return *(char*)b - *(char*)a;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[20001], B[20001];
        scanf("%s", A);
        scanf("%s", B);
        int len = strlen(A);
        qsort(A, len, sizeof(char), compare);
        qsort(B, len, sizeof(char), compare);
        int i = 0, j = 0;
        while (i < len && j < len) {
            if (A[i] > B[j]) {
                if (A[i] == '4' || A[i] == '7') {
                    printf("%c", A[i]);
                }
                i++;
            } else if (A[i] < B[j]) {
                if (B[j] == '4' || B[j] == '7') {
                    printf("%c", B[j]);
                }
                j++;
            } else {
                if (A[i] == '4' || A[i] == '7') {
                    printf("%c", A[i]);
                }
                i++;
                j++;
            }
        }
        printf("\n");
    }
    return 0;
}

